// Filter for articles that need processing.
// Catches 'pending' and also 'processing' articles stuck from previous failed runs.
const items = $input.all();
const toProcess = items.filter(item => {
  const status = (item.json.seo_status || '').toString().trim().toLowerCase();
  return status === 'pending' || status === 'processing';
});
if (toProcess.length === 0) {
  // Nothing to process — return empty to stop execution
  return [];
}
return toProcess;

// Idempotency check: does this article_id already exist in Sheet B?
const targetId = $node['Lock Record'].json.article_id;
const allSeoRows = $input.all();

const alreadyProcessed = allSeoRows.some(
  row => row.json.article_id && row.json.article_id.toString().trim() === targetId.toString().trim()
);

// Pass through all original article data from the locked record
return [{
  json: {
    already_processed: alreadyProcessed,
    article_id:        targetId,
    title:             $node['Lock Record'].json.title,
    content:           $node['Lock Record'].json.content,
    category:          $node['Lock Record'].json.category || ''
  }
}];

// Parse OpenAI response — handle all response formats safely
const openaiItem = $input.first().json;
const raw = openaiItem.message?.content
  || openaiItem.choices?.[0]?.message?.content
  || openaiItem.text
  || '';

const articleId = $node['Check Idempotency'].json.article_id;

let seo;
try {
  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim();
  seo = JSON.parse(cleaned);
} catch (e) {
  throw new Error('OpenAI JSON parse error: ' + e.message + ' | Raw: ' + raw.slice(0, 300));
}

// Validate required fields exist
if (!Array.isArray(seo.primary_keywords)) throw new Error('Missing primary_keywords in SEO response');
if (!Array.isArray(seo.long_tail_keywords)) throw new Error('Missing long_tail_keywords in SEO response');
if (!seo.meta_title) throw new Error('Missing meta_title in SEO response');
if (!seo.meta_description) throw new Error('Missing meta_description in SEO response');

// Enforce character limits
const metaTitle = seo.meta_title.slice(0, 60);
const metaDesc  = seo.meta_description.slice(0, 155);

return [{
  json: {
    article_id:            articleId,
    processed_at:          new Date().toISOString(),
    primary_keywords_csv:  seo.primary_keywords.join(', '),
    long_tail_keywords_csv: seo.long_tail_keywords.join(', '),
    meta_title:            metaTitle,
    meta_description:      metaDesc,
    openai_raw:            raw,
    ranking_insights:      JSON.stringify(seo.ranking_insights || {})
  }
}];

// Capture the error from OpenAI node failure
const errorMsg = $input.first().json.error?.message
  || $input.first().json.message
  || 'Unknown SEO processing error';

// Get article_id from the Check Idempotency node context
const articleId = $node['Check Idempotency'].json.article_id;

return [{
  json: {
    article_id: articleId,
    error_message: errorMsg
  }
}];
